import{c as t,Q as n,j as a,m as o}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"How do I create a new tenant?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/create-tenant.md","filePath":"guide/recipes/admin/create-tenant.md","lastUpdated":1778912818000}'),r={name:"guide/recipes/admin/create-tenant.md"};function s(i,e,l,c,d,h){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="how-do-i-create-a-new-tenant" tabindex="-1">How do I create a new tenant? <a class="header-anchor" href="#how-do-i-create-a-new-tenant" aria-label="Permalink to &quot;How do I create a new tenant?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong>, <strong>Infra Ops</strong>, <strong>Account Manager</strong> (within scope), or <strong>QA Admin</strong> (within both customer and instance scope).<br><strong>Customer Admins</strong> can also create tenants from the Customer Portal, subject to plan limits.</p></div><p>A tenant is a logical workspace inside an instance. Creating one provisions the schema and binds it to a customer + an instance.</p><h2 id="from-the-admin-console" tabindex="-1">From the Admin Console <a class="header-anchor" href="#from-the-admin-console" aria-label="Permalink to &quot;From the Admin Console&quot;">​</a></h2><ol><li>Open <strong>Tenants</strong> in the sidebar and click <strong>New Tenant</strong>.</li><li>Fill in: <ul><li><strong>Name</strong> — e.g. <code>Acme PROD</code>.</li><li><strong>Customer</strong> — pick from the dropdown.</li><li><strong>Instance</strong> — pick the hosting instance. QA Admins see only their scoped instances.</li><li><strong>Environment</strong> — <code>production</code>, <code>staging</code>, <code>development</code>, or <code>sandbox</code>.</li><li><strong>User license count</strong> — initial seat count for billing.</li></ul></li><li>Click <strong>Create</strong>.</li></ol><h2 id="from-the-customer-portal" tabindex="-1">From the Customer Portal <a class="header-anchor" href="#from-the-customer-portal" aria-label="Permalink to &quot;From the Customer Portal&quot;">​</a></h2><p>If you&#39;re a Customer Owner or Admin and your plan allows self-serve tenant creation:</p><ol><li>Open <strong>Tenants</strong> in the portal sidebar.</li><li>Click <strong>New Tenant</strong>.</li><li>Pick a name and environment. The instance is chosen for you based on your plan.</li><li>Click <strong>Create</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The tenant appears in the table with status <strong>Provisioning</strong>, then flips to <strong>Active</strong> when the underlying instance finishes setup. Users can be <a href="./../portal/assign-user-to-tenant">assigned</a> once status is Active.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../portal/assign-user-to-tenant">How do I assign a user to a tenant?</a></li><li><a href="./create-instance">How do I create a new instance?</a></li></ul>',12)])])}const u=t(r,[["render",s]]);export{g as __pageData,u as default};
